const therapistResponses = {
  anger: [
    "It sounds like a lot of anger is coming up. What happened?",
    "Anger can be really heavy. Want to talk about what triggered it?",
    "I hear your frustration. Let’s slow this down together."
  ],

  sadness: [
    "I’m really glad you told me this. That sounds painful.",
    "Feeling this way can be exhausting. I’m here with you.",
    "You don’t have to go through this alone."
  ],

  anxiety: [
    "That sounds overwhelming. Let’s take one step at a time.",
    "Your feelings make sense given what you’re experiencing.",
    "Try taking a slow breath with me right now."
  ],

  happiness: [
    "That’s great to hear! What’s been going well?",
    "Moments like these matter. Tell me more.",
    "I’m happy you’re feeling this way 🌱"
  ],

  neutral: [
    "I’m listening. Tell me more about what’s on your mind.",
    "Take your time. There’s no rush here.",
    "I’m here with you."
  ]
};

export function getTherapistReply(mood) {
  const responses = therapistResponses[mood] || therapistResponses.neutral;
  return responses[Math.floor(Math.random() * responses.length)];
}
